import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

const val BASE_URL_DEV = "https://api.example.com/dev"
const val BASE_URL_STAGING = "https://api.example.com/staging"
const val BASE_URL_PROD = "https://api.example.com"

fun getApiUrl(isDev: Boolean, isStaging: Boolean): String {
    return if (isDev) BASE_URL_DEV
    else if (isStaging) BASE_URL_STAGING
    else BASE_URL_PROD
}

class AuthInterceptor(private val token: String) : Interceptor {

    override fun intercept(chain:Interceptor.Chain): Response {
        val request = chain.request()
            .newBuilder()
            .addHeader("Authorization", "Bearer $token")
            .build()

        return chain.proceed(request)
    }
}

fun getApi(token: String, isDev: Boolean, isStaging: Boolean): UserApi {
    val apiUrl = getApiUrl(isDev, isStaging)

    val httpClient = OkHttpClient.Builder()
        .addInterceptor(HttpLoggingInterceptor().setLevel(HttpLoggingInterceptor.Level.BODY))
        .build()

    return Retrofit.Builder()
        .baseUrl(apiUrl)
        .client(httpClient)
        .addConverterFactory(GsonConverterFactory.create())
        .build()
        .create(UserApi::class.java)
}

interface UserApi {

    @GET("/users")
    fun getUsers(): Call<List<User>>
}

data class User(val id: Int, val name: String, val email: String)

// Example usage
fun main() {
    val token = "your-auth-token"
    val isDev = false
    val api = getApi(token, isDev, true)
    val response = api.getUsers().execute()
    println(response.body())
